suppressMessages({library(dada2); library(devtools); load_all(".", quiet=TRUE); library(testthat)})
files <- c("test_beta_div.R","test_alpha_div.R")
for (f in files) {
  r <- tryCatch(as.data.frame(test_file(file.path("tests/testthat", f), reporter="silent")),
                error=function(e) {cat(f, "LOAD ERROR:", conditionMessage(e), "\n"); NULL})
  if (!is.null(r)) {
    cat(sprintf("%-22s PASS:%d FAIL:%d WARN:%d SKIP:%d\n", f, sum(r$passed), sum(r$failed), sum(r$warning), sum(r$skipped)))
    bad <- r[r$failed>0 | r$error,]
    if(nrow(bad)) for(i in seq_len(nrow(bad))) cat("   FAIL:", bad$test[i], "\n")
  }
}
